def evaluate(expr: str) -> float:
    tokens = tokenize(expr)
    if not tokens:
        raise ValueError("Empty expression")

    parser = Parser(tokens)
    result = parser.parse_expr()

    if parser.pos < len(tokens):
        raise ValueError("Unexpected tokens after expression")

    return result

def tokenize(expr: str) -> list:
    tokens = []
    i = 0
    while i < len(expr):
        if expr[i].isspace():
            i += 1
        elif expr[i].isdigit() or expr[i] == '.':
            j = i
            while j < len(expr) and (expr[j].isdigit() or expr[j] == '.'):
                j += 1
            try:
                tokens.append(('NUMBER', float(expr[i:j])))
            except ValueError:
                raise ValueError(f"Invalid number: {expr[i:j]}")
            i = j
        elif expr[i:i+2] == '**':
            tokens.append(('**', '**'))
            i += 2
        elif expr[i] in '+-*/()':
            tokens.append((expr[i], expr[i]))
            i += 1
        else:
            raise ValueError(f"Unexpected character: {expr[i]}")

    return tokens

class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def current_token(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self):
        token = self.current_token()
        self.pos += 1
        return token

    def parse_expr(self):
        left = self.parse_term()
        while self.current_token() and self.current_token()[0] in '+-':
            op = self.consume()[0]
            right = self.parse_term()
            if op == '+':
                left = left + right
            else:
                left = left - right
        return left

    def parse_term(self):
        left = self.parse_power()
        while self.current_token() and self.current_token()[0] in '*/':
            op = self.consume()[0]
            right = self.parse_power()
            if op == '*':
                left = left * right
            else:
                if right == 0:
                    raise ZeroDivisionError("division by zero")
                left = left / right
        return left

    def parse_power(self):
        unary_ops = []
        while self.current_token() and self.current_token()[0] in '+-':
            unary_ops.append(self.consume()[0])

        value = self.parse_atom()

        if self.current_token() and self.current_token()[0] == '**':
            self.consume()
            right = self.parse_power()
            value = value ** right

        for op in reversed(unary_ops):
            if op == '-':
                value = -value

        return value

    def parse_atom(self):
        token = self.current_token()
        if token is None:
            raise ValueError("Unexpected end of input")

        if token[0] == 'NUMBER':
            self.consume()
            return token[1]
        elif token[0] == '(':
            self.consume()
            value = self.parse_expr()
            if self.current_token() is None or self.current_token()[0] != ')':
                raise ValueError("Unmatched parentheses")
            self.consume()
            return value
        else:
            raise ValueError("Invalid expression")
